form:Form.form:Scripts:
		var arrData = new Array();

function EnabledBtnSend(isEnabledBtnSend){
	if(isEnabledBtnSend){
		Ctrl("btnAceptar").SetEnabled(true);
	}else{
		Ctrl("btnAceptar").SetEnabled(false);
	}
} 

function Form_OnLoad() {
	LoadReporte();
	Ctrl("btnAceptar").SetEnabled(false);
	arrData["oi_legajo"] = undefined;
	arrData["oi_liquidacion"] = undefined;
}                       

function LoadReporte(){
			var reporte = Ctrl("reporte").GetCValue();
			Ctrl("controlReporte").SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&amp;file="+reporte+"&amp;oi_usuario_sistema="+GetProxy().Etty()+"&amp;crc="+Ctrl('crc').GetXValue());
			//Ctrl("controlReporte").SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&amp;file=NucleusWF.Base.Ejecucion.BaseInicioWF.rpt&amp;oi_usuario_sistema="+Ctrl("oi_usuario_sistema").GetCValue()+"&amp;reporte="+Ctrl("nombre_reporte").GetCValue());
}

function SetParam(param,value){
	arrData[param] = value;
}

function ShowFormulario649(){
	if(arrData["oi_legajo"] != undefined && arrData["oi_legajo"] != null && arrData["oi_legajo"] != ""){
		if(arrData["oi_liquidacion"] != undefined && arrData["oi_liquidacion"] != null && arrData["oi_liquidacion"] != ""){
			if(arrData["oi_empresa"] != undefined && arrData["oi_empresa"] != null && arrData["oi_empresa"] != ""){
			//Ejecuto el flow que dispara el reporte del recibo de sueldo.
			Ctrl("oi_liquidacion").SetXValue(arrData["oi_liquidacion"]);
			Ctrl("oi_personal_emp").SetXValue(arrData["oi_legajo"]);
			Ctrl("oi_empresa").SetXValue(arrData["oi_empresa"]);
			Ctrl("l_anioAnterior").SetXValue(Ctrl('s').GetXValue());
			Ctrl("main").DoEvent("ACCEPT");
			}else{
				alert("Falta seleccionar una empresa para poder ver el formulario 649");			
			}
		}else{
			alert("Falta seleccionar una liquidación para poder ver el formulario 649");		
		}
	}else{
		alert("Falta seleccionar legajo para poder ver el formulario 649");
	}                                                                                                                                                                                                        
}   

function ObjtectResult()
{
	this.processResult= function(xmlin){}
}
